-- lua_compile/init.lua -- public facade for the SpongeJIT LuaCompile rewrite.

local M = {}

M.schema = require("lua_compile.schema")
M.builders = require("lua_compile.builders")
M.validate = require("lua_compile.validate")
M.diagnostics = require("lua_compile.diagnostics")
M.errors = require("lua_compile.errors")

M.lua_compile_unit = require("lua_compile.lua_compile_unit")
M.lua_compile_to_normal_form = require("lua_compile.lua_compile_to_normal_form")
M.lua_compile_to_lalin_kernel = require("lua_compile.lua_compile_to_lalin_kernel")
M.lua_compile_validate = require("lua_compile.lua_compile_validate")

function M.unit_from_events(events, observations)
  return M.lua_compile_unit.from_events(events, observations)
end

function M.compile_to_normal_form(unit)
  return M.lua_compile_to_normal_form.compile(unit)
end

function M.compile_to_lalin_kernel(unit)
  return M.lua_compile_to_lalin_kernel.compile(unit)
end

return M

-- lua_compile_unit.lua -- LuaCompile.Unit construction.

local B = require("lua_compile.builders")
local Collect = require("lua_compile.lua_src_window_collect")
local FactObserve = require("lua_compile.lua_fact_from_runtime_observe")

local M = {}

function M.from_parts(source_window, evidence)
  return B.LuaCompile.Unit(source_window, evidence or B.empty_evidence())
end

function M.from_events(events, observations)
  local window = Collect.collect(events or {})
  local evidence = FactObserve.observe(observations or {})
  return M.from_parts(window, evidence)
end

return M

-- lua_compile/builders.lua -- constructor conveniences only.
--
-- These helpers are syntax sugar over ASDL constructors. They do not perform
-- semantic lowering, optimization, fallback, or backend decisions.

local Schema = require("lua_compile.schema")
local T = Schema.get()

local M = { T = T, LuaSrc = T.LuaSrc, LuaRegion = T.LuaRegion, LuaFact = T.LuaFact, LuaSem = T.LuaSem, LuaNF = T.LuaNF, LuaContract = T.LuaContract, LalinOut = T.LalinOut, LuaCompile = T.LuaCompile }

local Src, Fact, Region = T.LuaSrc, T.LuaFact, T.LuaRegion

function M.pc(n) return Src.Pc(tonumber(n) or 0) end
function M.slot(n) return Src.Slot(tonumber(n) or 0) end
function M.up(n) return Src.UpRef(tonumber(n) or 0) end
function M.k(n) return Src.KRef(tonumber(n) or 0) end
function M.imm(n) return Src.Imm(tonumber(n) or 0) end
function M.count(n) return Src.Count(tonumber(n) or 0) end
function M.offset(n) return Src.Offset(tonumber(n) or 0) end
function M.ax(n) return Src.Ax(tonumber(n) or 0) end
function M.r(slot) return Src.R(M.slot(slot)) end
function M.kr(k) return Src.K(M.k(k)) end

function M.window(ops) return Src.Window(ops or {}) end
function M.region_set(regions) return Region.RegionSet(regions or {}) end
function M.empty_evidence()
  return Fact.Evidence({}, {}, M.region_set({}))
end
function M.unit(window, evidence)
  return T.LuaCompile.Unit(window, evidence or M.empty_evidence())
end

function M.src_slot_subject(slot)
  return Fact.SrcSlot(type(slot) == "table" and slot or M.slot(slot))
end
function M.const_subject(k)
  return Fact.Const(type(k) == "table" and k or M.k(k))
end
function M.fact(subject, predicate, value_key, deps)
  return Fact.Fact(subject, predicate, value_key or "", deps or {})
end
function M.slot_fact(slot, predicate, value_key, deps)
  return M.fact(M.src_slot_subject(slot), predicate, value_key, deps)
end

return M

-- lua_src_window_collect.lua -- opcode stream -> LuaSrc.Window.

local B = require("lua_compile.builders")
local Decode = require("lua_compile.lua_src_from_puc_decode")

local M = {}

function M.collect(events)
  local ops = {}
  for i, ev in ipairs(events or {}) do ops[i] = Decode.decode(ev) end
  return B.window(ops)
end

return M

-- lua_src_validate.lua -- source-layer checks only.

local Validate = require("lua_compile.validate")

local M = {}

function M.validate(window)
  return Validate.lua_src_window(window)
end

return M

-- lua_sem_env.lua -- virtual slot/value environment.

local B = require("lua_compile.builders")
local Sem = B.LuaSem

local Env = {}
Env.__index = Env

function Env.new()
  return setmetatable({ aliases = {}, values = {}, next_value_id = 1 }, Env)
end

function Env:slot_class(slot)
  local id = type(slot) == "table" and slot.id or tonumber(slot) or 0
  return Sem.SlotClass(id)
end

function Env:alias(slot, first_pc, last_pc)
  local id = type(slot) == "table" and slot.id or tonumber(slot) or 0
  if not self.aliases[id] then self.aliases[id] = Sem.SlotAlias(type(slot) == "table" and slot or B.slot(id), Sem.SlotClass(id), first_pc or B.pc(0), last_pc or first_pc or B.pc(0)) end
  return self.aliases[id]
end

function Env:slot_value(slot)
  return Sem.SlotValue(self:slot_class(slot))
end

function Env:next_value()
  local id = self.next_value_id
  self.next_value_id = id + 1
  return Sem.ValueId(id)
end

function Env:aliases_array()
  local keys, out = {}, {}
  for k in pairs(self.aliases) do keys[#keys + 1] = k end
  table.sort(keys)
  for _, k in ipairs(keys) do out[#out + 1] = self.aliases[k] end
  return out
end

return Env

-- lua_sem_guard.lua -- semantic guard construction and success facts.

local B = require("lua_compile.builders")
local Sem, Fact = B.LuaSem, B.LuaFact

local M = {}

function M.fact_guard(subject, predicate, value, deps, pc)
  return Sem.FactGuard(subject, predicate, value, deps or {}, type(pc) == "table" and pc or B.pc(pc))
end

function M.observe(guard)
  return Sem.Observe(Sem.GuardObservation(guard))
end

function M.i64_slot_guard(slot, pc)
  local subject = Fact.SrcSlot(type(slot) == "table" and slot or B.slot(slot))
  local value = Sem.SlotValue(Sem.SlotClass(subject.slot.id))
  return M.fact_guard(subject, Fact.IsI64, value, {}, pc)
end

return M

-- lua_sem_write.lua -- semantic writes, kills, barriers.

local B = require("lua_compile.builders")
local Sem = B.LuaSem

local M = {}

function M.slot(slot_class, value)
  return Sem.DoWrite(Sem.SlotWrite(slot_class, value))
end

function M.field(address, value)
  return Sem.DoWrite(Sem.FieldWrite(address, value))
end

function M.barrier(owner, value, payload)
  return Sem.BarrierAfterStore(owner, value, payload)
end

return M

-- lua_sem_reject.lua -- structured semantic rejection reasons.

local Errors = require("lua_compile.errors")

local M = {}

function M.reject(op, reason, missing_facts, missing_payloads)
  return Errors.result_reject(op and op.pc or 0, reason or "unsupported_semantic_case", op, missing_facts or {}, missing_payloads or {})
end

return M

-- lua_nf_write_reduce.lua -- dead write/value reduction.

local M = {}
function M.final_slot_writes(slot_values, live_slots)
  local out = {}
  local keys = {}
  local live = nil
  if live_slots then live = {}; for _, id in ipairs(live_slots) do live[id] = true end end
  for id in pairs(slot_values or {}) do if not live or live[id] then keys[#keys + 1] = id end end
  table.sort(keys)
  for _, id in ipairs(keys) do out[#out + 1] = { slot = id, value = slot_values[id] } end
  return out
end
return M

-- lua_contract_dependency.lua -- epoch/dependency extraction.

local M = {}
function M.collect_from_facts(facts)
  local seen, out = {}, {}
  for _, f in ipairs(facts or {}) do for _, d in ipairs(f.deps or {}) do if not seen[d] then seen[d] = true; out[#out + 1] = d end end end
  return out
end
return M

-- lua_place_validate.lua -- non-semantic placement invariants.

local Schema = require("lua_compile.schema")
local pvm = require("lalin.pvm")
local T = Schema.get()
local M = {}
function M.validate(plan)
  if pvm.classof(plan) ~= T.LuaPlace.Plan then return false, { "expected LuaPlace.Plan" } end
  return true, {}
end
return M

-- lua_compile_validate.lua -- whole-pipeline invariants.

local Schema = require("lua_compile.schema")
local pvm = require("lalin.pvm")
local T = Schema.get()
local M = {}

function M.validate_result(result)
  if not T.LuaCompile.Result.members[pvm.classof(result)] then return false, { "expected LuaCompile.Result" } end
  return true, {}
end

return M

